// Parsuj sitemap_index.xml a vráť len obsahové sitemaps
const xmlText = $json.data || '';

const relevantPatterns = [
  'post-sitemap.xml',
  'terminologia-sitemap.xml',
  'hub-destinacii-sitemap.xml'
];

const sitemapBlocks = xmlText.match(/<sitemap>[\s\S]*?<\/sitemap>/g) || [];

const result = [];
for (const block of sitemapBlocks) {
  const locMatch = block.match(/<loc>(.*?)<\/loc>/);
  if (!locMatch) continue;
  const url = locMatch[1].trim();

  const matched = relevantPatterns.find(p => url.includes(p));
  if (!matched) continue;

  let post_type = 'posts';
  if (url.includes('terminologia')) post_type = 'terminologia';
  else if (url.includes('hub-destinacii')) post_type = 'hub-destinacii';

  result.push({ json: { sitemap_url: url, post_type } });
}

if (result.length === 0) {
  throw new Error('[Parse Sitemaps] Žiadne relevantné sitemaps nenájdené. Skontroluj site_url v Set Config.');
}

console.log(`[Parse Sitemaps] Nájdených ${result.length} sitemáp: ${result.map(r => r.json.post_type).join(', ')}`);
return result;

const siteLabel = $('Set Config').first().json.site_label;
const output = [];

for (const item of items) {
  const xml = item.json.data || '';
  const postType = item.json.post_type || 'posts';

  const urlBlocks = xml.match(/<url>[\s\S]*?<\/url>/g) || [];

  for (const block of urlBlocks) {
    const locMatch     = block.match(/<loc>(.*?)<\/loc>/);
    const lastmodMatch = block.match(/<lastmod>(.*?)<\/lastmod>/);
    if (!locMatch) continue;

    const url     = locMatch[1].trim();
    const lastmod = lastmodMatch ? lastmodMatch[1].trim() : '';
    const cleanUrl = url.replace(/\/$/, '');
    const slug = cleanUrl.split('/').pop();
    if (!slug) continue;

    output.push({
      json: {
        _source:        'sitemap',
        wp_id:          '',
        post_type:      postType,
        slug,
        title:          '',
        status:         'publish',
        date_published: lastmod,
        date_modified:  lastmod,
        link:           url,
        site_url:       siteLabel
      }
    });
  }
}

console.log(`[Parse Sitemap URLs] Celkovo URL: ${output.length}`);
return output.length > 0 ? output : [{ json: { _source: 'sitemap', slug: null, wp_id: null } }];

const sitemapItems = items.filter(i => i.json._source === 'sitemap');
const sheetItems   = items.filter(i => i.json._source === 'sheet');

console.log(`[Find New] Sitemap URL: ${sitemapItems.length} | Sheets riadkov: ${sheetItems.length}`);

const trackedSlugs = new Set(
  sheetItems
    .map(i => String(i.json.slug || '').trim())
    .filter(Boolean)
);

const newPosts = sitemapItems.filter(
  i => i.json.slug && !trackedSlugs.has(String(i.json.slug).trim())
);

console.log(`[Find New] Nových postov na pridanie: ${newPosts.length}`);

if (newPosts.length === 0) {
  return [{ json: { has_new: false, count: 0 } }];
}

return newPosts.map(i => ({
  json: {
    has_new:           true,
    wp_id:             '',
    post_type:         i.json.post_type,
    slug:              i.json.slug,
    title:             '',
    status:            'publish',
    date_published:    i.json.date_published,
    date_modified:     i.json.date_modified,
    link:              i.json.link,
    extraction_status: 'pending',
    gdoc_id:           '',
    gdoc_url:          '',
    extracted_at:      '',
    site_url:          i.json.site_url
  }
}));

const pending = items.filter(i => {
  const status = String(i.json.extraction_status || '').trim().toLowerCase();
  return status === 'pending';
});

if (pending.length === 0) {
  console.log('[Filter] Žiadne pending posty – všetko spracované.');
  return [{ json: { has_pending: false, count: 0 } }];
}

console.log(`[Filter] Pending postov na spracovanie: ${pending.length}`);
return pending;

function getInnerText(html) {
  if (!html) return '';
  return html
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#039;/g, "'").replace(/&nbsp;/g, ' ')
    .replace(/&ndash;/g, '–').replace(/&mdash;/g, '—').replace(/&hellip;/g, '…')
    .replace(/&#\d+;/g, '').trim();
}

function htmlToCleanWP(html) {
  if (!html) return '';
  let c = html;
  c = c.replace(/\[[^\]]*\]/g, '');
  c = c.replace(/<script[\s\S]*?<\/script>/gi, '');
  c = c.replace(/<style[\s\S]*?<\/style>/gi, '');
  c = c.replace(/<noscript[\s\S]*?<\/noscript>/gi, '');
  c = c.replace(/<figure[\s\S]*?<\/figure>/gi, '');
  c = c.replace(/<picture[\s\S]*?<\/picture>/gi, '');
  c = c.replace(/<img[^>]*\/?>/gi, '');
  c = c.replace(/<video[\s\S]*?<\/video>/gi, '');
  c = c.replace(/<audio[\s\S]*?<\/audio>/gi, '');
  c = c.replace(/<iframe[\s\S]*?<\/iframe>/gi, '');
  c = c.replace(/<svg[\s\S]*?<\/svg>/gi, '');
  c = c.replace(/<source[^>]*\/?>/gi, '');
  c = c.replace(/<\/?(?:div|section|article|aside|header|footer|nav|main|span|figure|figcaption)[^>]*>/gi, '');
  c = c.replace(/<a\s+[^>]*?href=["']([^"']*)["'][^>]*>/gi, '<a href="$1">');
  const allowedTags = 'h1|h2|h3|h4|h5|h6|p|ul|ol|li|table|thead|tbody|tfoot|tr|th|td|strong|b|em|i|blockquote|br|hr';
  c = c.replace(new RegExp(`<(${allowedTags})\\s+[^>]*>`, 'gi'), (_, tag) => `<${tag.toLowerCase()}>`);
  const keepPattern = new RegExp(`</?(?:${allowedTags}|a)(?:\\s[^>]*)?>`, 'gi');
  const placeholder = {};
  let pIdx = 0;
  c = c.replace(keepPattern, (match) => { const key = `__KEEP${pIdx}__`; placeholder[key] = match; pIdx++; return key; });
  c = c.replace(/<[^>]+>/g, '');
  for (const [key, val] of Object.entries(placeholder)) { c = c.replace(key, val); }
  c = c.replace(/<p>\s*<\/p>/gi, '');
  c = c.replace(/<p>&nbsp;<\/p>/gi, '');
  c = c.replace(/<p>\s*<br>\s*<\/p>/gi, '');
  c = c.replace(/&nbsp;/g, ' ').replace(/&ndash;/g, '–').replace(/&mdash;/g, '—').replace(/&hellip;/g, '…');
  return c.replace(/\n{3,}/g, '\n\n').trim();
}

const origSlug     = $('Filter Pending Only').item?.json?.slug     || $json.slug || 'unknown';
const origPostType = $('Filter Pending Only').item?.json?.post_type || $json.post_type || 'unknown';

if ($json.error || ($json.statusCode !== undefined && $json.statusCode >= 400) || $json.code) {
  console.log(`[Prepare Content] SKIP – HTTP chyba pre slug: ${origSlug}`);
  return { json: { _skip: true, _skip_reason: 'http_error', slug: origSlug, post_type: origPostType } };
}

const post = Array.isArray($json) ? ($json[0] || null) : $json;
if (!post || !post.id) {
  console.log(`[Prepare Content] SKIP – Post nenájdený pre slug: ${origSlug}`);
  return { json: { _skip: true, _skip_reason: 'post_not_found', slug: origSlug, post_type: origPostType } };
}

const wpId          = String(post.id);
const titleRaw      = post.title?.rendered   || 'Bez názvu';
const contentRaw    = post.content?.rendered || '';
const title         = getInnerText(titleRaw);
const datePublished = post.date     || '';
const dateModified  = post.modified || '';
const link          = post.link     || '';
const slug          = post.slug     || '';
const postType      = post.type     || '';
const siteLabel     = $('Set Config').first().json.site_label;
const folderId      = $('Set Config').first().json.gdrive_folder_id;

const contentHtmlClean = htmlToCleanWP(contentRaw);

const safeTitle = title.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const metaRows = [
  `<tr><td><strong>URL</strong></td><td><a href="${link}">${link}</a></td></tr>`,
  `<tr><td><strong>WP ID</strong></td><td>${wpId}</td></tr>`,
  `<tr><td><strong>Slug</strong></td><td>${slug}</td></tr>`,
  `<tr><td><strong>Typ</strong></td><td>${postType}</td></tr>`,
  `<tr><td><strong>Publikované</strong></td><td>${datePublished.substring(0,10)}</td></tr>`,
  `<tr><td><strong>Upravené</strong></td><td>${dateModified.substring(0,10)}</td></tr>`,
  `<tr><td><strong>Web</strong></td><td>${siteLabel}</td></tr>`,
].join('');

const content_gdoc_html = `<!DOCTYPE html>\n<html><head><meta charset="UTF-8"></head><body>\n<h1>${safeTitle}</h1>\n<table>${metaRows}</table>\n<hr>\n${contentHtmlClean}\n</body></html>`;

const content_html = [
  `<!-- WP ID: ${wpId} | SLUG: ${slug} | TYP: ${postType} -->`,
  `<!-- TITULOK: ${title} -->`,
  `<!-- URL: ${link} -->`,
  `<!-- PUBLIKOVANÉ: ${datePublished} | UPRAVENÉ: ${dateModified} -->`,
  '',
  contentHtmlClean
].join('\n');

console.log(`[Prepare Content] OK – slug: ${slug} | wp_id: ${wpId} | title: ${title.substring(0,60)}`);

return {
  json: {
    _skip:            false,
    wp_id:            wpId,
    title,
    slug,
    link,
    date_published:   datePublished,
    date_modified:    dateModified,
    post_type:        postType,
    site_url:         siteLabel,
    content_gdoc_html,
    content_html,
    doc_title:        `[${wpId}] ${title}`,
    doc_title_html:   `[${wpId}] ${title} – HTML`,
    gdrive_folder_id: folderId
  }
};

return {
  json: {
    title:         $('Prepare Content').item.json.title,
    slug:          $('Prepare Content').item.json.slug,
    wp_id:         $('Prepare Content').item.json.wp_id,
    post_type:     $('Prepare Content').item.json.post_type,
    gdoc_url:      'https://docs.google.com/document/d/' + $('Docs Create (Upload HTML→GDoc)').item.json.id + '/edit',
    gdoc_html_url: 'https://docs.google.com/document/d/' + $('Docs Create HTML').item.json.id + '/edit'
  }
};

const posts = $input.first().json.posts || [];
const count = posts.length;

if (count === 0) {
  return [{ json: { skip: true, message: '' } }];
}

const typeIcon = (type) => {
  if (type === 'terminologia') return '📚';
  if (type === 'hub-destinacii') return '🗺️';
  return '📄';
};

const lines = posts.map(p =>
  `${typeIcon(p.post_type)} <${p.gdoc_url}|${p.title}> · <${p.gdoc_html_url}|HTML>\n   \`${p.slug}\` · WP ID: ${p.wp_id}`
);

const message = [
  `✅ *Extrakcia do Google Docs dokončená*`,
  ``,
  `📊 Extrahovaných článkov: *${count}*`,
  `📁 Priečinok: <https://drive.google.com/drive/folders/1p3jPAIZBJKRHNCF-q4MMr6eTtdNGemFa|mojastranka_allposts>`,
  ``,
  ...lines
].join('\n');

console.log(`[Build Slack Summary] Správa pre ${count} postov pripravená.`);
return [{ json: { skip: false, count, message } }];

const sitemapItems = items.filter(i => i.json._source === 'sitemap');
const sheetItems   = items.filter(i => i.json._source === 'sheet');

const sheetBySlug = {};
for (const i of sheetItems) {
  const slug = String(i.json.slug || '').trim();
  if (slug) sheetBySlug[slug] = i.json;
}

const modified = [];

for (const si of sitemapItems) {
  const slug = String(si.json.slug || '').trim();
  if (!slug) continue;

  const row = sheetBySlug[slug];
  if (!row) continue;

  const status = String(row.extraction_status || '').trim().toLowerCase();
  if (status === 'pending' || status === '') continue;

  const sitemapDate = String(si.json.date_modified || '').substring(0, 10);
  const sheetDate   = String(row.date_modified   || '').substring(0, 10);

  if (!sitemapDate || !sheetDate) continue;
  if (sitemapDate <= sheetDate) continue;

  console.log(`[Find Modified] Zmena detekovaná: ${slug} | sheet: ${sheetDate} → sitemap: ${sitemapDate} | status: ${status}`);

  modified.push({
    json: {
      has_modified:  true,
      slug,
      post_type:     String(row.post_type  || si.json.post_type || ''),
      date_modified: si.json.date_modified,
      link:          si.json.link || String(row.link || ''),
      site_url:      String(row.site_url   || si.json.site_url || ''),
      gdoc_id:       String(row.gdoc_id      || '').trim(),
      gdoc_html_id:  String(row.gdoc_html_id || '').trim()
    }
  });
}

console.log(`[Find Modified] Celkovo zmenených postov: ${modified.length}`);

if (modified.length === 0) {
  return [{ json: { has_modified: false, count: 0 } }];
}

return modified;

const out = [];

for (const item of items) {
  const base = {
    slug:          item.json.slug,
    post_type:     item.json.post_type,
    date_modified: item.json.date_modified,
    link:          item.json.link,
    site_url:      item.json.site_url
  };

  const gdocId     = item.json.gdoc_id;
  const gdocHtmlId = item.json.gdoc_html_id;

  if (gdocId) {
    out.push({ json: { ...base, doc_id: gdocId } });
  }
  if (gdocHtmlId) {
    out.push({ json: { ...base, doc_id: gdocHtmlId } });
  }
  if (!gdocId && !gdocHtmlId) {
    out.push({ json: { ...base, doc_id: null } });
  }
}

const realDeletions = out.filter(i => i.json.doc_id !== null).length;
console.log(`[Prepare Doc IDs] Items na zmazanie: ${realDeletions} | Total items: ${out.length}`);
return out;

const seen = new Set();
const out  = [];

for (const item of items) {
  const slug = String(item.json.slug || '').trim();
  if (!slug) continue;
  if (seen.has(slug)) continue;
  seen.add(slug);
  out.push({
    json: {
      slug:          item.json.slug,
      post_type:     item.json.post_type,
      date_modified: item.json.date_modified,
      link:          item.json.link,
      site_url:      item.json.site_url
    }
  });
}

console.log(`[Deduplicate Slugs] Unikátnych slugov na Sheets reset: ${out.length}`);
return out.length > 0 ? out : [{ json: { slug: null } }];

const count = items.length;
const typeIcon = (type) => {
  if (type === 'terminologia') return '📚';
  if (type === 'hub-destinacii') return '🗺️';
  return '📄';
};
const lines = items.map(i => `${typeIcon(i.json.post_type)} \`${i.json.slug}\` → nový lastmod: ${String(i.json.date_modified || '').substring(0, 10)}`).join('\n');
const message = [
  `🔄 *moja-stranka.sk – Upravené články – re-extrakcia spustená v tomto behu*`,
  ``,
  `📊 Počet resetovaných a re-extrahovaných: *${count}*`,
  `⚡ GDocs budú vytvorené v tomto behu (nie až o 6h)`,
  ``,
  lines
].join('\n');
return [{ json: { message } }];
